create table teams (
    team_id      number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    team_code    varchar2(12 byte) not null enable,
    team_name    varchar2(80 byte) not null enable,
    city         varchar2(80 byte) not null enable,
    arena_name   varchar2(120 byte),
    founded_year number(4, 0),
    active_flag  char(1 byte) default 'Y' not null enable,
    created_at   timestamp(6) default systimestamp not null enable
);

alter table teams
    add constraint teams_active_ck
        check ( active_flag in ( 'Y', 'N' ) ) enable;

alter table teams add constraint teams_code_uk unique ( team_code )
    using index enable;

alter table teams
    add constraint teams_pk primary key ( team_id )
        using index enable;

